public class BasicSyntax {
    public static void main(String[] args) {

        // Variables and Data Types
        int age = 30; // Integer - whole number
        double price = 19.99; // Double - floating-point number (decimal)
        boolean isStudent = true; // Boolean - true or false
        char initial = 'J'; // Character - single letter or symbol
        String name = "John Doe"; // String - sequence of characters

        // Displaying variable values
        System.out.println("Name: " + name);
        System.out.println("Age: " + age);
        System.out.println("Price: " + price);
        System.out.println("Is Student: " + isStudent);
        System.out.println("Initial: " + initial);

        // Type Casting
        double anotherPrice = 10;
        int roundedPrice = (int) anotherPrice; // Explicitly casting double to int (truncates decimal)
        System.out.println("Rounded Price: " + roundedPrice); // Output: 10

        int num1 = 5;
        double result = num1; // Implicit casting from int to double (no data loss)
        System.out.println("Result: " + result); // Output: 5.0

        // Constants
        final double PI = 3.14159; // 'final' keyword makes PI a constant
        // PI = 3.14; // This would cause a compilation error because you can't change a constant
        System.out.println("PI: " + PI);

        //String Concatenation
        String greeting = "Hello, " + name + "!";
        System.out.println(greeting);

    }
}

public class OperatorsAndExpressions {

    public static void main(String[] args) {

        // Arithmetic Operators
        int num1 = 10;
        int num2 = 5;
        int sum = num1 + num2; // Addition
        int difference = num1 - num2; // Subtraction
        int product = num1 * num2; // Multiplication
        int quotient = num1 / num2; // Integer Division
        double remainder = num1 % num2; // Modulus (remainder of division)

        System.out.println("Sum: " + sum);
        System.out.println("Difference: " + difference);
        System.out.println("Product: " + product);
        System.out.println("Quotient: " + quotient);
        System.out.println("Remainder: " + remainder);

        // Comparison Operators
        boolean isEqual = (num1 == num2); // Equal to
        boolean isNotEqual = (num1 != num2); // Not equal to
        boolean isGreaterThan = (num1 > num2); // Greater than
        boolean isLessThan = (num1 < num2); // Less than
        boolean isGreaterOrEqual = (num1 >= num2); // Greater than or equal to
        boolean isLessOrEqual = (num1 <= num2); // Less than or equal to

        System.out.println("Is equal: " + isEqual);
        System.out.println("Is not equal: " + isNotEqual);

        // Logical Operators
        boolean condition1 = true;
        boolean condition2 = false;
        boolean andResult = condition1 && condition2; // Logical AND
        boolean orResult = condition1 || condition2; // Logical OR
        boolean notResult = !condition1; // Logical NOT

        System.out.println("AND: " + andResult);
        System.out.println("OR: " + orResult);
        System.out.println("NOT: " + notResult);

        // Assignment Operators
        int x = 5;
        x += 3; // Equivalent to x = x + 3
        System.out.println("x += 3: " + x);

        // Operator Precedence (PEMDAS/BODMAS)
        int result = 2 + 3 * 4; // Multiplication happens before addition
        System.out.println("2 + 3 * 4 = " + result); // Output: 14

        // Increment/Decrement Operators
        int count = 0;
        count++; // Post-increment (count is incremented after the expression)
        System.out.println("count++: " + count);

        int y = 5;
        --y; // Pre-decrement (y is decremented before the expression)
        System.out.println("--y: " + y);
    }
}

public class ControlFlowExample {

    public static void main(String[] args) {

        // If-Else Statement
        int age = 20;
        if (age >= 18) {
            System.out.println("You are eligible to vote!");
        } else {
            System.out.println("You are not yet eligible to vote.");
        }

        // Switch Statement
        String dayOfWeek = "Monday";
        switch (dayOfWeek) {
            case "Monday":
                System.out.println("Start of the work week.");
                break;
            case "Friday":
                System.out.println("Almost weekend!");
                break;
            default:
                System.out.println("Just another day.");
        }

        // For Loop
        System.out.println("\nCounting from 1 to 5 using a for loop:");
        for (int i = 1; i <= 5; i++) {
            System.out.println(i);
        }

        // While Loop
        System.out.println("\nCounting down from 5 to 1 using a while loop:");
        int count = 5;
        while (count > 0) {
            System.out.println(count);
            count--;
        }

        // Do-While Loop
        System.out.println("\nDo-While loop example (always executes at least once):");
        int j = 0;
        do {
            System.out.println(j);
            j++;
        } while (j < 3);

        // Break Statement
        System.out.println("\nUsing break to exit a loop early:");
        for (int k = 1; k <= 10; k++) {
            if (k == 5) {
                break; // Exit the loop when k is 5
            }
            System.out.println(k);
        }

        // Continue Statement
        System.out.println("\nUsing continue to skip an iteration:");
        for (int l = 1; l <= 5; l++) {
            if (l == 3) {
                continue; // Skip printing 3
            }
            System.out.println(l);
        }
    }
}

public class ArraysAndStrings {

    public static void main(String[] args) {

        // Array Declaration and Initialization
        int[] numbers = {10, 20, 30, 40, 50};
        String[] names = new String[3]; // Declaring an array of Strings with a size of 3
        names[0] = "Alice";
        names[1] = "Bob";
        names[2] = "Charlie";

        // Array Manipulation
        System.out.println("Original array: ");
        printArray(numbers);

        // Adding a new element (requires creating a new array)
        int[] newNumbers = new int[numbers.length + 1];
        System.arraycopy(numbers, 0, newNumbers, 0, numbers.length);
        newNumbers[numbers.length] = 60;
        numbers = newNumbers; // Update the reference
        System.out.println("Array after adding 60: ");
        printArray(numbers);

        // Multi-dimensional Array
        int[][] matrix = {{
            1, 2, 3
        }, {
            4, 5, 6
        }, {
            7, 8, 9
        }};

        System.out.println("Matrix element at [1][1]: " + matrix[1][1]);

        // String Methods
        String message = "  Hello, World!  ";
        String trimmedMessage = message.trim(); // Removes leading and trailing whitespace
        String upperCaseMessage = trimmedMessage.toUpperCase();
        String subString = trimmedMessage.substring(0, 5); // Extracts "Hello"
        int index = trimmedMessage.indexOf("World");

        System.out.println("Trimmed: " + trimmedMessage);
        System.out.println("Uppercase: " + upperCaseMessage);
        System.out.println("Substring: " + subString);
        System.out.println("Index of 'World': " + index);

        // StringBuilder and StringBuffer
        StringBuilder sb = new StringBuilder();
        sb.append("This is a");
        sb.append(" StringBuilder.");
        System.out.println("StringBuilder: " + sb.toString());

        StringBuffer sf = new StringBuffer();
        sf.append("This is a");
        sf.append(" StringBuffer.");
        System.out.println("StringBuffer: " + sf.toString());

    }

    // Helper method to print an array
    public static void printArray(int[] arr) {
        for (int i = 0; i < arr.length; i++) {
            System.out.print(arr[i] + " ");
        }
        System.out.println();
    }
}

public class BankAccount {

    private double balance; // Private instance variable - encapsulation
    private String accountHolderName;

    // Constructor
    public BankAccount(String name, double initialBalance) {
        this.accountHolderName = name;
        this.balance = initialBalance;
    }

    // Getter for balance - controlled access
    public double getBalance() {
        return balance;
    }

    // Setter for balance - controlled modification
    public void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            System.out.println("Deposited: " + amount);
        } else {
            System.out.println("Invalid deposit amount.");
        }
    }

    public void withdraw(double amount) {
        if (amount > 0 && amount <= balance) {
            balance -= amount;
            System.out.println("Withdrawn: " + amount);
        } else {
            System.out.println("Insufficient funds or invalid withdrawal amount.");
        }
    }

    // Method overloading - same name, different parameters
    public void displayAccountInfo() {
        System.out.println("Account Holder: " + accountHolderName);
        System.out.println("Balance: " + balance);
    }

    public void displayAccountInfo(String currency) {
        System.out.println("Account Holder: " + accountHolderName);
        System.out.println("Balance: " + balance + " " + currency);
    }

    public static void main(String[] args) {
        BankAccount myAccount = new BankAccount("Alice Smith", 1000.0);
        myAccount.displayAccountInfo(); // Calls the first overloaded method
        myAccount.displayAccountInfo("USD"); // Calls the second overloaded method
        myAccount.deposit(500.0);
        myAccount.withdraw(200.0);
        System.out.println("Current Balance: " + myAccount.getBalance());
    }
}

public class Animal {
    // Attributes (data)
    private String name;
    private String sound;

    // Constructor
    public Animal(String name, String sound) {
        this.name = name;
        this.sound = sound;
    }

    // Method
    public void makeSound() {
        System.out.println(this.name + " says " + this.sound + "!");
    }

    // Getter for name
    public String getName() {
        return name;
    }

    // Setter for name
    public void setName(String name) {
        this.name = name;
    }

}

// Inheritance: Dog extends Animal
class Dog extends Animal {
    private String breed;

    public Dog(String name, String breed) {
        super(name, "Woof!"); // Call the Animal constructor
        this.breed = breed;
    }

    public String getBreed() {
        return breed;
    }

    @Override // Override the makeSound method
    public void makeSound() {
        System.out.println(getName() + " the " + breed + " barks: " + getSound() + "!");
    }
}

// Inheritance: Cat extends Animal
class Cat extends Animal {
    public Cat(String name) {
        super(name, "Meow!");
    }

    @Override
    public void makeSound() {
        System.out.println(getName() + " says: " + getSound() + "!");
    }
}

// Interface
interface Flyable {
    void fly();
}

// Abstract Class
abstract class Bird extends Animal implements Flyable {
    public Bird(String name) {
        super(name, "Chirp!");
    }

    @Override
    public void fly() {
        System.out.println(getName() + " is flying!");
    }

    // Abstract method - must be implemented by subclasses
    public abstract void migrate();
}

// Concrete subclass of Bird
class Eagle extends Bird {
    @Override
    public void migrate() {
        System.out.println("Eagle is migrating south for the winter.");
    }
}

public class Main {
    public static void main(String[] args) {
        Animal genericAnimal = new Animal("Generic Animal", "Generic Sound");
        genericAnimal.makeSound();

        Dog myDog = new Dog("Buddy", "Golden Retriever");
        myDog.makeSound();
        System.out.println("Dog's breed: " + myDog.getBreed());

        Cat myCat = new Cat("Whiskers");
        myCat.makeSound();

        Eagle myEagle = new Eagle("Baldy");
        myEagle.makeSound();
        myEagle.fly();
        myEagle.migrate();

        // Polymorphism in action
        Animal animal1 = new Dog("Rover", "Labrador");
        Animal animal2 = new Cat("Mittens");
        animal1.makeSound(); // Calls Dog's makeSound()
        animal2.makeSound(); // Calls Cat's makeSound()
    }
}

import java.util.*;

class InsufficientFundsException extends Exception {
    public InsufficientFundsException(String message) {
        super(message);
    }
}

public class ExceptionCollections {

    public static void main(String[] args) {
        // Demonstrate Exception Handling
        double balance = 100.0;
        double withdrawalAmount = 150.0;

        try {
            withdraw(balance, withdrawalAmount);
            System.out.println("Withdrawal successful.");
        } catch (InsufficientFundsException e) {
            System.err.println("Error: " + e.getMessage());
        } finally {
            System.out.println("Transaction attempt completed."); //Always executes
        }

        // Demonstrate ArrayList
        ArrayList<String> names = new ArrayList<>();
        names.add("Alice");
        names.add("Bob");
        names.add("Charlie");

        System.out.println("ArrayList: " + names);

        // Demonstrate LinkedList
        LinkedList<String> linkedList = new LinkedList<>(names); //Initialize with ArrayList
        linkedList.addFirst("David");
        linkedList.addLast("Eve");
        System.out.println("LinkedList: " + linkedList);

        // Demonstrate HashMap
        HashMap<String, Integer> ageMap = new HashMap<>();
        ageMap.put("Alice", 30);
        ageMap.put("Bob", 25);
        ageMap.put("Charlie", 35);

        System.out.println("HashMap: " + ageMap);

        // Demonstrate HashSet
        HashSet<String> uniqueNames = new HashSet<>(names); //Initialize with ArrayList
        uniqueNames.add("Alice"); //Duplicate - won't be added
        System.out.println("HashSet: " + uniqueNames);

        // Demonstrate Iterator
        Iterator<String> iterator = names.iterator();
        System.out.println("Iterating through ArrayList:");
        while (iterator.hasNext()) {
            String name = iterator.next();
            System.out.println(name);
        }
    }

    public static void withdraw(double balance, double amount) throws InsufficientFundsException {
        if (amount > balance) {
            throw new InsufficientFundsException("Insufficient funds. Balance: " + balance + ", Withdrawal amount: " + amount);
        }
        // Simulate withdrawal
        balance -= amount;
    }
}
